const LanguageSwitcher = ({ 
  variant = 'default', // 'default', 'compact', 'icon-only'
  showNativeNames = true,
  className = '',
  ...props 
}) => {
  const { currentLanguage, languages, changeLanguage, getCurrentLanguage } = useLocalization();
  const [isOpen, setIsOpen] = useState(false);
  const containerRef = useRef(null);

  const currentLang = getCurrentLanguage();

  // Close dropdown when clicking outside
  useEffect(() => {
    const handleClickOutside = (event) => {
      if (containerRef.current && !containerRef.current.contains(event.target)) {
        setIsOpen(false);
      }
    };

    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  // Close dropdown on escape key
  useEffect(() => {
    const handleEscape = (event) => {
      if (event.key === 'Escape') {
        setIsOpen(false);
      }
    };

    document.addEventListener('keydown', handleEscape);
    return () => document.removeEventListener('keydown', handleEscape);
  }, []);

  const handleLanguageChange = (langCode) => {
    changeLanguage(langCode);
    setIsOpen(false);
  };

  const toggleDropdown = () => {
    setIsOpen(!isOpen);
  };

  // Compact variant - just flag and code
  if (variant === 'compact') {
    return (
      <SwitcherContainer ref={containerRef} className={className} {...props}>
        <CompactSwitcher
          onClick={toggleDropdown}
          whileHover={{ scale: 1.05 }}
          whileTap={{ scale: 0.95 }}
        >
          <span className="flag">{currentLang.flag}</span>
          <span>{currentLang.code.toUpperCase()}</span>
        </CompactSwitcher>

        <AnimatePresence>
          {isOpen && (
            <DropdownMenu
              initial={{ opacity: 0, y: -10, scale: 0.95 }}
              animate={{ opacity: 1, y: 0, scale: 1 }}
              exit={{ opacity: 0, y: -10, scale: 0.95 }}
              transition={{ duration: 0.2 }}
            >
              {languages.map((language) => (
                <LanguageOption
                  key={language.code}
                  onClick={() => handleLanguageChange(language.code)}
                  className={currentLanguage === language.code ? 'active' : ''}
                  whileHover={{ backgroundColor: 'rgba(139, 69, 19, 0.05)' }}
                  whileTap={{ scale: 0.98 }}
                >
                  <span className="flag">{language.flag}</span>
                  <div className="language-info">
                    <span className="language-name">{language.name}</span>
                    {showNativeNames && (
                      <span className="native-name">{language.nativeName}</span>
                    )}
                  </div>
                </LanguageOption>
              ))}
            </DropdownMenu>
          )}
        </AnimatePresence>
      </SwitcherContainer>
    );
  }

  // Icon-only variant
  if (variant === 'icon-only') {
    return (
      <SwitcherContainer ref={containerRef} className={className} {...props}>
        <CompactSwitcher
          onClick={toggleDropdown}
          whileHover={{ scale: 1.1 }}
          whileTap={{ scale: 0.9 }}
          style={{ padding: '0.5rem', borderRadius: '50%' }}
        >
          <FiGlobe size={18} />
        </CompactSwitcher>

        <AnimatePresence>
          {isOpen && (
            <DropdownMenu
              initial={{ opacity: 0, y: -10, scale: 0.95 }}
              animate={{ opacity: 1, y: 0, scale: 1 }}
              exit={{ opacity: 0, y: -10, scale: 0.95 }}
              transition={{ duration: 0.2 }}
            >
              {languages.map((language) => (
                <LanguageOption
                  key={language.code}
                  onClick={() => handleLanguageChange(language.code)}
                  className={currentLanguage === language.code ? 'active' : ''}
                  whileHover={{ backgroundColor: 'rgba(139, 69, 19, 0.05)' }}
                  whileTap={{ scale: 0.98 }}
                >
                  <span className="flag">{language.flag}</span>
                  <div className="language-info">
                    <span className="language-name">{language.name}</span>
                    {showNativeNames && (
                      <span className="native-name">{language.nativeName}</span>
                    )}
                  </div>
                </LanguageOption>
              ))}
            </DropdownMenu>
          )}
        </AnimatePresence>
      </SwitcherContainer>
    );
  }

  // Default variant - full dropdown
  return (
    <SwitcherContainer ref={containerRef} className={className} {...props}>
      <SwitcherButton
        onClick={toggleDropdown}
        $isOpen={isOpen}
        whileHover={{ scale: 1.02 }}
        whileTap={{ scale: 0.98 }}
      >
        <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem' }}>
          <span className="flag">{currentLang.flag}</span>
          <span>{currentLang.name}</span>
        </div>
        <FiChevronDown className="chevron" size={16} />
      </SwitcherButton>

      <AnimatePresence>
        {isOpen && (
          <DropdownMenu
            initial={{ opacity: 0, y: -10, scale: 0.95 }}
            animate={{ opacity: 1, y: 0, scale: 1 }}
            exit={{ opacity: 0, y: -10, scale: 0.95 }}
            transition={{ duration: 0.2 }}
          >
            {languages.map((language) => (
              <LanguageOption
                key={language.code}
                onClick={() => handleLanguageChange(language.code)}
                className={currentLanguage === language.code ? 'active' : ''}
                whileHover={{ backgroundColor: 'rgba(139, 69, 19, 0.05)' }}
                whileTap={{ scale: 0.98 }}
              >
                <span className="flag">{language.flag}</span>
                <div className="language-info">
                  <span className="language-name">{language.name}</span>
                  {showNativeNames && (
                    <span className="native-name">{language.nativeName}</span>
                  )}
                </div>
              </LanguageOption>
            ))}
          </DropdownMenu>
        )}
      </AnimatePresence>
    </SwitcherContainer>
  );
};

export default LanguageSwitcher;
